```javascript
// lib/order_processor.js
const db = require('./db');
const payment = require('./payment');
const inventory = require('./inventory');
const notifier = require('./notifier');

function processOrder(orderId, userId, items, callback) {
  db.startTransaction((err, tx) => {
    if (err) return callback(err);
    inventory.reserve(tx, items, (err, reservation) => {
      if (err) {
        tx.rollback(() => callback(err));
        return;
      }
      payment.charge(userId, reservation.total, (err, charge) => {
        if (err) {
          inventory.release(tx, reservation.id, () => {
            tx.rollback(() => callback(err));
          });
          return;
        }
        db.saveOrder(tx, orderId, {
          userId, items, reservationId: reservation.id, chargeId: charge.id
        }, (err, order) => {
          if (err) {
            payment.refund(charge.id, () => {
              inventory.release(tx, reservation.id, () => {
                tx.rollback(() => callback(err));
              });
            });
            return;
          }
          tx.commit((err) => {
            if (err) return callback(err);
            notifier.send(userId, 'order_placed', order, (notifyErr) => {
              if (notifyErr) console.warn('notify failed:', notifyErr);
              callback(null, order);
            });
          });
        });
      });
    });
  });
}

module.exports = { processOrder };
```

